selector_to_html = {"a[href=\"#src.importer.transform._handle_categorical_units\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform._handle_categorical_units\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_handle_categorical_units</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#_handle_categorical_units\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Assign integer values and a sentinel unit to categorical records.</p><p>Rows without a <code class=\"docutils literal notranslate\"><span class=\"pre\">unit</span></code> value are treated as categorical.  Their string <code class=\"docutils literal notranslate\"><span class=\"pre\">value</span></code>\nis resolved to a signed integer/NaN via <a class=\"reference internal\" href=\"#src.importer.transform._map_categories\" title=\"src.importer.transform._map_categories\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">_map_categories()</span></code></a>, and their <code class=\"docutils literal notranslate\"><span class=\"pre\">unit</span></code>\nis set to <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">CATEGORICAL</span></code>. For <cite>type</cite>/<cite>value</cite> pairs\nin <code class=\"docutils literal notranslate\"><span class=\"pre\">KNOWN_CATEGORY_TYPE_VIOLATIONS</span></code> <cite>type</cite> is updated.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.endDate\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.endDate\">\n<span class=\"sig-name descname\"><span class=\"pre\">endDate</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/typing.html#typing.Any\" title=\"(in Python v3.14)\"><span class=\"pre\">Any</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.pipeline._HealthRow\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">class</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.pipeline.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_HealthRow</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"o\"><span class=\"pre\">*</span></span><span class=\"n\"><span class=\"pre\">args</span></span></em>, <em class=\"sig-param\"><span class=\"o\"><span class=\"pre\">**</span></span><span class=\"n\"><span class=\"pre\">kwargs</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/pipeline.html#_HealthRow\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/typing.html#typing.Protocol\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">Protocol</span></code></a></p><p>Row attributes consumed by <a class=\"reference internal\" href=\"#src.importer.pipeline._add_row_to_pipeline\" title=\"src.importer.pipeline._add_row_to_pipeline\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">_add_row_to_pipeline()</span></code></a>.</p><p>Structural type matching what <code class=\"docutils literal notranslate\"><span class=\"pre\">df.itertuples()</span></code> yields for a\nwell-formed health DataFrame. Only the attributes actually read are\nrequired; extra attributes on the namedtuple are ignored.</p></dd>", "a[href=\"#src.importer.response.BatchFailure.to_dict\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure.to_dict\">\n<span class=\"sig-name descname\"><span class=\"pre\">to_dict</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#BatchFailure.to_dict\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Serialise to a JSON-compatible dictionary.</p><p>Example:</p></dd>", "a[href=\"#src.importer.response.RowFailure.to_dict\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.to_dict\">\n<span class=\"sig-name descname\"><span class=\"pre\">to_dict</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#RowFailure.to_dict\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Serialise to a JSON-compatible dictionary.</p><p>Example:</p></dd>", "a[href=\"#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Importer<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\u00b6</a></h2><p id=\"module-src.importer.importer\">Health Data Importer.</p><p>Uploads Apple Health <code class=\"docutils literal notranslate\"><span class=\"pre\">export.zip</span></code> data to a local Redis TimeSeries database\nvia an Extract \u2192 Transform \u2192 Load (ETL) pipeline.</p>", "a[href=\"#src.importer.importer.HealthDataImporter._write_failures_file\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter._write_failures_file\">\n<span class=\"sig-name descname\"><span class=\"pre\">_write_failures_file</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">failures</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter._write_failures_file\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Serialise <em>failures</em> and write them to <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures_file</span></code>.</p><p>Overwrites any existing file so the file always reflects the current state.</p><p>Example:</p></dd>", "a[href=\"#src.importer.transform.transform\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform.transform\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">transform</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#transform\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Clean and reshape <em>df</em> in-place for upload to Redis TimeSeries.</p><p>Applies the following steps in order:</p><p>Example:</p></dd>", "a[href=\"#src.importer.importer.HealthDataImporter._update_failures_file\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter._update_failures_file\">\n<span class=\"sig-name descname\"><span class=\"pre\">_update_failures_file</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter._update_failures_file\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd></dd>", "a[href=\"#src.importer.response.failures_to_json\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.failures_to_json\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">failures_to_json</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">failures</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#failures_to_json\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Serialise a list of <a class=\"reference internal\" href=\"#src.importer.response.UploadFailure\" title=\"src.importer.response.UploadFailure\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">UploadFailure</span></code></a> objects to a JSON string.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.unit\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.unit\">\n<span class=\"sig-name descname\"><span class=\"pre\">unit</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.transform._drop_null_values\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform._drop_null_values\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_drop_null_values</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#_drop_null_values\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Drop rows with a <code class=\"docutils literal notranslate\"><span class=\"pre\">NaN</span></code> <code class=\"docutils literal notranslate\"><span class=\"pre\">value</span></code> field and log the count.</p><p>Mutates <em>df</em> in-place.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._resolve_failures\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._resolve_failures\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.pipeline.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_resolve_failures</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">response</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/pipeline.html#_resolve_failures\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Inspect a pipeline response and record per-row failures.</p><p>Maps the flat <em>response</em> list back to individual rows using the\n<code class=\"docutils literal notranslate\"><span class=\"pre\">response[2i]</span> <span class=\"pre\">/</span> <span class=\"pre\">response[2i+1]</span></code> convention (start / end command per\nrow <em>i</em>).  Successful commands return an <code class=\"docutils literal notranslate\"><span class=\"pre\">int</span></code> (the stored timestamp);\nfailed commands return a <a class=\"reference external\" href=\"https://redis.readthedocs.io/en/stable/exceptions.html#redis.exceptions.ResponseError\" title=\"(in redis-py v7.4.0)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">ResponseError</span></code></a> object\nwhen the pipeline was executed with <code class=\"docutils literal notranslate\"><span class=\"pre\">raise_on_error=False</span></code>.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline.upload_batch\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline.upload_batch\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.pipeline.</span></span><span class=\"sig-name descname\"><span class=\"pre\">upload_batch</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">rts</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">duplicate_policy</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">DuplicatePolicy.FIRST</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/pipeline.html#upload_batch\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Upload data slice to Redis TimeSeries via a single pipeline.</p><p>All <code class=\"docutils literal notranslate\"><span class=\"pre\">TS.ADD</span></code> commands for the slice are batched into one\n<code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">Pipeline</span></code> and flushed in a single\nnetwork round-trip.  <code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">Pipeline.execute()</span></code> is called with\n<code class=\"docutils literal notranslate\"><span class=\"pre\">raise_on_error=False</span></code> so that individual command failures are returned\nas <a class=\"reference external\" href=\"https://redis.readthedocs.io/en/stable/exceptions.html#redis.exceptions.ResponseError\" title=\"(in redis-py v7.4.0)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">ResponseError</span></code></a> objects in the response list\nrather than raised as exceptions, enabling granular\n<code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">RowFailure</span></code> reporting.</p><p>Failure semantics:</p><p>Response mapping (two <code class=\"docutils literal notranslate\"><span class=\"pre\">TS.ADD</span></code> commands per row):</p><p>Example:</p></dd>", "a[href=\"#module-src.importer.parser\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Parser<a class=\"headerlink\" href=\"#module-src.importer.parser\" title=\"Link to this heading\">\u00b6</a></h2><p>Parser for Apple Health export files.</p><p>Reads the export.zip produced by the Apple Health app and returns a single\ntidy DataFrame that can be saved to by the caller.</p>", "a[href=\"#src.importer.transform._map_categories\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform._map_categories\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_map_categories</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">no_unit</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#_map_categories\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Replace categorical string values with integer values in-place.</p><p>Example:</p></dd>", "a[href=\"#src.importer.response.RowFailure.row_index\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.row_index\">\n<span class=\"sig-name descname\"><span class=\"pre\">row_index</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/typing.html#typing.Any\" title=\"(in Python v3.14)\"><span class=\"pre\">Any</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.response.failures_from_json\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.failures_from_json\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">failures_from_json</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">text</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#failures_from_json\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Deserialise a JSON string produced by <a class=\"reference internal\" href=\"#src.importer.response.failures_to_json\" title=\"src.importer.response.failures_to_json\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">failures_to_json()</span></code></a>.</p><p>Example:</p></dd>", "a[href=\"#src.importer.importer.HealthDataImporter\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">class</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.importer.</span></span><span class=\"sig-name descname\"><span class=\"pre\">HealthDataImporter</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">connection</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">data_dir</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">'data'</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">in_file</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">'export.zip'</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">working_dir</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">out_file</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">'export.feather'</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">failures_file</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">'upload_failures.json'</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/functions.html#object\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">object</span></code></a></p><p>Import Apple Health export data into Redis TimeSeries.</p><p>After calling <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.etl\" title=\"src.importer.importer.HealthDataImporter.etl\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">etl()</span></code></a> or <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.update\" title=\"src.importer.importer.HealthDataImporter.update\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">update()</span></code></a>, any upload failures are\naccessible via <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures</span></code> and persisted to <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures_file</span></code>\nso that <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.retry_failed\" title=\"src.importer.importer.HealthDataImporter.retry_failed\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">retry_failed()</span></code></a> can be called in a later Python session.</p><p>Example:</p></dd>", "a[href=\"#src.importer.importer.HealthDataImporter.etl\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter.etl\">\n<span class=\"sig-name descname\"><span class=\"pre\">etl</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"keyword-only-separator o\"><abbr title=\"Keyword-only parameters separator (PEP 3102)\"><span class=\"pre\">*</span></abbr></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">write_feather</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">False</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">persist_failures</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">no_cache</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">False</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter.etl\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Run the full Extract \u2192 Transform \u2192 Load pipeline.</p><p>Uses <code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">DuplicatePolicy.First</span></code> so that re-running the same export\nnever overwrites existing data points.  To overwrite, use\n<a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.update\" title=\"src.importer.importer.HealthDataImporter.update\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">update()</span></code></a> instead.</p><p>When setting <cite>persist_failures=True</cite> any upload failures <strong>overwrite</strong>\n<code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures_file</span></code> so that <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.retry_failed\" title=\"src.importer.importer.HealthDataImporter.retry_failed\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">retry_failed()</span></code></a> can be called in\nanother Python session:</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow._is_protocol\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow._is_protocol\">\n<span class=\"sig-name descname\"><span class=\"pre\">_is_protocol</span></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">True</span></span></dt><dd></dd>", "a[href=\"#src.importer.importer.HealthDataImporter.update\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter.update\">\n<span class=\"sig-name descname\"><span class=\"pre\">update</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"keyword-only-separator o\"><abbr title=\"Keyword-only parameters separator (PEP 3102)\"><span class=\"pre\">*</span></abbr></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">write_feather</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">False</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">persist_failures</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">no_cache</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">False</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter.update\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Re-import the export, <strong>overwriting</strong> existing data points.</p><p>Identical to <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.etl\" title=\"src.importer.importer.HealthDataImporter.etl\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">etl()</span></code></a> except it uses <code class=\"docutils literal notranslate\"><span class=\"pre\">DuplicatePolicy.LAST</span></code>,\nwhich means any timestamp that already exists in Redis is overwritten\nwith the new value rather than kept.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.startDate\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.startDate\">\n<span class=\"sig-name descname\"><span class=\"pre\">startDate</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/typing.html#typing.Any\" title=\"(in Python v3.14)\"><span class=\"pre\">Any</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.importer.HealthDataImporter.retry_failed\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter.retry_failed\">\n<span class=\"sig-name descname\"><span class=\"pre\">retry_failed</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"keyword-only-separator o\"><abbr title=\"Keyword-only parameters separator (PEP 3102)\"><span class=\"pre\">*</span></abbr></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">persist_failures</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter.retry_failed\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Re-attempt uploading every data point recorded in <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures_file</span></code>.</p><p>Reads the failures JSON file written by the most recent <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.etl\" title=\"src.importer.importer.HealthDataImporter.etl\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">etl()</span></code></a>,\n<a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.update\" title=\"src.importer.importer.HealthDataImporter.update\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">update()</span></code></a>, or previous <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.retry_failed\" title=\"src.importer.importer.HealthDataImporter.retry_failed\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">retry_failed()</span></code></a> call which <strong>overwrites</strong>\n<code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures</span></code>. This method can be called in a completely separate Python\nsession as long as the failures file and the Feather cache still exist:</p><p>Retry behaviour:</p><p>Loads dataframe from <cite>self.out_file</cite> and finds entries that failed to upload,\nand passes this subset to <a class=\"reference internal\" href=\"#src.importer.importer._load\" title=\"src.importer.importer._load\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">_load()</span></code></a>.</p><p>After the retry:</p><p>Example:</p></dd>", "a[href=\"#src.importer.parser.parse_apple_health\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.parser.parse_apple_health\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.parser.</span></span><span class=\"sig-name descname\"><span class=\"pre\">parse_apple_health</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">zip_path</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/parser.html#parse_apple_health\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Parse an Apple Health export archive into a DataFrame.</p><p>Reads all Record elements from the export.xml inside the given export.zip\nand returns them as a single tidy DataFrame with timezone-aware datetime\ncolumns. The output schema is a superset of the one produced by\napple-health-exporter\u2019s health_xml_to_feather, adding device, sourceVersion,\nand creationDate columns.</p></dd>", "a[href=\"#src.importer.response.BatchFailure.data_type\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure.data_type\">\n<span class=\"sig-name descname\"><span class=\"pre\">data_type</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.parser.NoHealthDataError\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.parser.NoHealthDataError\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">exception</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.parser.</span></span><span class=\"sig-name descname\"><span class=\"pre\">NoHealthDataError</span></span><a class=\"reference internal\" href=\"_modules/src/importer/parser.html#NoHealthDataError\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/exceptions.html#ValueError\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">ValueError</span></code></a></p><p>Raised when trying to parse a zip file without usable data.</p></dd>", "a[href=\"#src.importer.response.RowFailure.data_type\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.data_type\">\n<span class=\"sig-name descname\"><span class=\"pre\">data_type</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.response.BatchFailure.__str__\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure.__str__\">\n<span class=\"sig-name descname\"><span class=\"pre\">__str__</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#BatchFailure.__str__\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Create human-readable string representation of this failure.</p></dd>", "a[href=\"#src.importer.transform._timestamps_to_unix\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform._timestamps_to_unix\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_timestamps_to_unix</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">series</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#_timestamps_to_unix\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Convert a <code class=\"docutils literal notranslate\"><span class=\"pre\">datetime64</span></code> Series to Unix timestamps in whole seconds.</p><p>Divides the nanosecond epoch integer representation by 10\u2079 using integer\nfloor division to avoid floating-point rounding errors.</p><p>Example:</p></dd>", "a[href=\"#src.importer.response.BatchFailure\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">class</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">BatchFailure</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">data_type</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">error</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#BatchFailure\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/functions.html#object\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">object</span></code></a></p><p>Records a failed upload for an entire data-type batch.</p><p>Produced by <a class=\"reference internal\" href=\"#src.importer.pipeline.upload_batch\" title=\"src.importer.pipeline.upload_batch\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">upload_batch()</span></code></a> when the pipeline itself\nraises a <a class=\"reference external\" href=\"https://redis.readthedocs.io/en/stable/exceptions.html#redis.exceptions.RedisError\" title=\"(in redis-py v7.4.0)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">RedisError</span></code></a> (e.g. a connection\nfailure, authentication error, or server-side crash).  In this case no\nrow-level response is available, so the entire batch is marked failed.</p><p>Example:</p></dd>", "a[href=\"#importer\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Importer<a class=\"headerlink\" href=\"#importer\" title=\"Link to this heading\">\u00b6</a></h1><h2>Importer<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\u00b6</a></h2><p id=\"module-src.importer.importer\">Health Data Importer.</p><p>Uploads Apple Health <code class=\"docutils literal notranslate\"><span class=\"pre\">export.zip</span></code> data to a local Redis TimeSeries database\nvia an Extract \u2192 Transform \u2192 Load (ETL) pipeline.</p>", "a[href=\"#src.importer.response.RowFailure.start_error\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.start_error\">\n<span class=\"sig-name descname\"><span class=\"pre\">start_error</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/constants.html#None\" title=\"(in Python v3.14)\"><span class=\"pre\">None</span></a></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">None</span></span></dt><dd></dd>", "a[href=\"#module-src.importer.transform\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Transform<a class=\"headerlink\" href=\"#module-src.importer.transform\" title=\"Link to this heading\">\u00b6</a></h2><p>Apple Health DataFrame transformation pipeline.</p><p>Provides public function <cite>transform</cite> that handles necessary transformations\nof raw Apple Health export data.</p>", "a[href=\"#src.importer.response.DuplicatePolicy\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.DuplicatePolicy\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">class</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">DuplicatePolicy</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"o\"><span class=\"pre\">*</span></span><span class=\"n\"><span class=\"pre\">values</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#DuplicatePolicy\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/enum.html#enum.Enum\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">Enum</span></code></a></p><p>Redis TimeSeries per-command duplicate-write strategy.</p><p><a class=\"reference internal\" href=\"#src.importer.response.DuplicatePolicy.FIRST\" title=\"src.importer.response.DuplicatePolicy.FIRST\"><code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">FIRST</span></code></a> is used by <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.etl\" title=\"src.importer.importer.HealthDataImporter.etl\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">etl()</span></code></a> for initial\nimports so that re-running an export never overwrites existing data points.\nIt is also used by <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.retry_failed\" title=\"src.importer.importer.HealthDataImporter.retry_failed\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">retry_failed()</span></code></a>.</p><p><a class=\"reference internal\" href=\"#src.importer.response.DuplicatePolicy.LAST\" title=\"src.importer.response.DuplicatePolicy.LAST\"><code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">LAST</span></code></a> is used by <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.update\" title=\"src.importer.importer.HealthDataImporter.update\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">update()</span></code></a> to overwrite\nexisting data points with new values.</p><p>Example:</p></dd>", "a[href=\"#module-src.importer.response\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Response<a class=\"headerlink\" href=\"#module-src.importer.response\" title=\"Link to this heading\">\u00b6</a></h2><p>Domain models for upload failure tracking and duplicate-write policy.</p><p>This module defines:</p>", "a[href=\"#module-src.importer.pipeline\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Pipeline<a class=\"headerlink\" href=\"#module-src.importer.pipeline\" title=\"Link to this heading\">\u00b6</a></h2><p>Redis TimeSeries pipeline upload helpers.</p><p>All writes to Redis TimeSeries are batched through a single\n<code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">Pipeline</span></code> per data-type call, reducing\nround-trips to one network exchange per type regardless of row count.</p>", "a[href=\"#src.importer.response.RowFailure\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">class</span></span><span class=\"w\"> </span></span><span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">RowFailure</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">data_type</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">row_index</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">start_error</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">end_error</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#RowFailure\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Bases: <a class=\"reference external\" href=\"https://docs.python.org/3/library/functions.html#object\" title=\"(in Python v3.14)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">object</span></code></a></p><p>Records a failed upload for a single DataFrame row.</p><p>Produced by <a class=\"reference internal\" href=\"#src.importer.pipeline.upload_batch\" title=\"src.importer.pipeline.upload_batch\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">upload_batch()</span></code></a> when one or both <code class=\"docutils literal notranslate\"><span class=\"pre\">TS.ADD</span></code>\ncommands for a specific row return a <a class=\"reference external\" href=\"https://redis.readthedocs.io/en/stable/exceptions.html#redis.exceptions.ResponseError\" title=\"(in redis-py v7.4.0)\"><code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">ResponseError</span></code></a>\ninside the pipeline response (i.e. the connection itself stayed up, but that\nindividual command failed).</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.type\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.type\">\n<span class=\"sig-name descname\"><span class=\"pre\">type</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.importer._load\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer._load\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.importer.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_load</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">r</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">duplicate_policy</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">DuplicatePolicy.FIRST</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#_load\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Batch-upload all records to Redis TimeSeries.</p><p>Each unique <code class=\"docutils literal notranslate\"><span class=\"pre\">type</span></code> is uploaded in its own pipeline transaction\nso that a failure in one type does not abort the others. Returns\na list of <code class=\"docutils literal notranslate\"><span class=\"pre\">UploadFailure</span></code> objects.</p><p>Example:</p></dd>", "a[href=\"#src.importer.response.BatchFailure.from_dict\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure.from_dict\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">classmethod</span></span><span class=\"w\"> </span></span><span class=\"sig-name descname\"><span class=\"pre\">from_dict</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">d</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#BatchFailure.from_dict\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Deserialise from a dictionary produced by <a class=\"reference internal\" href=\"#src.importer.response.BatchFailure.to_dict\" title=\"src.importer.response.BatchFailure.to_dict\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">to_dict()</span></code></a>.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.value\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.value\">\n<span class=\"sig-name descname\"><span class=\"pre\">value</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/typing.html#typing.Any\" title=\"(in Python v3.14)\"><span class=\"pre\">Any</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.response.DuplicatePolicy.FIRST\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.DuplicatePolicy.FIRST\">\n<span class=\"sig-name descname\"><span class=\"pre\">FIRST</span></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">'FIRST'</span></span></dt><dd></dd>", "a[href=\"#src.importer.response.UploadFailure\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.UploadFailure\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.response.</span></span><span class=\"sig-name descname\"><span class=\"pre\">UploadFailure</span></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">src.importer.response.RowFailure</span> <span class=\"pre\">|</span> <span class=\"pre\">src.importer.response.BatchFailure</span></span></dt><dd><p>Union type for a single upload failure \u2014 either a row-level or batch-level\nfailure.  Used as the element type of the failures list returned by\n<code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">_load()</span></code> and stored on the importer instance.</p></dd>", "a[href=\"#src.importer.response.RowFailure.__str__\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.__str__\">\n<span class=\"sig-name descname\"><span class=\"pre\">__str__</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#RowFailure.__str__\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Create human-readable string representation of this failure.</p></dd>", "a[href=\"#src.importer.response.RowFailure.from_dict\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.from_dict\">\n<span class=\"property\"><span class=\"k\"><span class=\"pre\">classmethod</span></span><span class=\"w\"> </span></span><span class=\"sig-name descname\"><span class=\"pre\">from_dict</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">d</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/response.html#RowFailure.from_dict\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Deserialise from a dictionary produced by <a class=\"reference internal\" href=\"#src.importer.response.RowFailure.to_dict\" title=\"src.importer.response.RowFailure.to_dict\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">to_dict()</span></code></a>.</p><p>Example:</p></dd>", "a[href=\"#src.importer.importer.HealthDataImporter._extract\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter._extract\">\n<span class=\"sig-name descname\"><span class=\"pre\">_extract</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"keyword-only-separator o\"><abbr title=\"Keyword-only parameters separator (PEP 3102)\"><span class=\"pre\">*</span></abbr></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">write_feather</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">no_cache</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter._extract\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Parse the Apple Health export and return a raw DataFrame.</p><p>Prefers the Feather cache at <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">output_file</span></code> to avoid re-running\nthe slow XML-to-Feather conversion.  Falls back to the ZIP export at\n<code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">zip_file</span></code> if no cache exists.</p><p>Example:</p></dd>", "a[href=\"#src.importer.pipeline._HealthRow.sourceName\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow.sourceName\">\n<span class=\"sig-name descname\"><span class=\"pre\">sourceName</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.response.BatchFailure.error\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.BatchFailure.error\">\n<span class=\"sig-name descname\"><span class=\"pre\">error</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a></span></dt><dd></dd>", "a[href=\"#src.importer.pipeline._HealthRow._abc_impl\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._HealthRow._abc_impl\">\n<span class=\"sig-name descname\"><span class=\"pre\">_abc_impl</span></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">&lt;_abc._abc_data</span> <span class=\"pre\">object&gt;</span></span></dt><dd></dd>", "a[href=\"#src.importer.importer.HealthDataImporter._read_failures_file\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter._read_failures_file\">\n<span class=\"sig-name descname\"><span class=\"pre\">_read_failures_file</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter._read_failures_file\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Read and deserialise the failures file.</p><p>Example:</p></dd>", "a[href=\"#src.importer.response.RowFailure.end_error\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.RowFailure.end_error\">\n<span class=\"sig-name descname\"><span class=\"pre\">end_error</span></span><span class=\"property\"><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/stdtypes.html#str\" title=\"(in Python v3.14)\"><span class=\"pre\">str</span></a><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><a class=\"reference external\" href=\"https://docs.python.org/3/library/constants.html#None\" title=\"(in Python v3.14)\"><span class=\"pre\">None</span></a></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">None</span></span></dt><dd></dd>", "a[href=\"#src.importer.response.DuplicatePolicy.LAST\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.response.DuplicatePolicy.LAST\">\n<span class=\"sig-name descname\"><span class=\"pre\">LAST</span></span><span class=\"property\"><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"pre\">'LAST'</span></span></dt><dd></dd>", "a[href=\"#src.importer.pipeline._add_row_to_pipeline\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.pipeline._add_row_to_pipeline\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.pipeline.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_add_row_to_pipeline</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">pipe</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">row</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">duplicate_policy</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">DuplicatePolicy.FIRST</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/pipeline.html#_add_row_to_pipeline\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Queue a single health record\u2019s start and end <code class=\"docutils literal notranslate\"><span class=\"pre\">TS.ADD</span></code> commands on <em>pipe</em>.</p><p>Two commands are issued per record:</p><p>The commands are not executed until\n<code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">execute()</span></code>\nis called by the caller, so this function is always O(1) and performs no\nnetwork I/O.</p><p>Example:</p></dd>", "a[href=\"#src.importer.importer.HealthDataImporter._delete_failures_file\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.importer.HealthDataImporter._delete_failures_file\">\n<span class=\"sig-name descname\"><span class=\"pre\">_delete_failures_file</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/importer.html#HealthDataImporter._delete_failures_file\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Delete <code class=\"xref py py-attr docutils literal notranslate\"><span class=\"pre\">failures_file</span></code> if it exists.</p><p>Called after a fully successful load or a fully successful retry to\nensure no stale file misleads a future <a class=\"reference internal\" href=\"#src.importer.importer.HealthDataImporter.retry_failed\" title=\"src.importer.importer.HealthDataImporter.retry_failed\"><code class=\"xref py py-meth docutils literal notranslate\"><span class=\"pre\">retry_failed()</span></code></a> call.</p><p>Example:</p></dd>", "a[href=\"#src.importer.transform._replace_known_violations\"]": "<dt class=\"sig sig-object py\" id=\"src.importer.transform._replace_known_violations\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">src.importer.transform.</span></span><span class=\"sig-name descname\"><span class=\"pre\">_replace_known_violations</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"_modules/src/importer/transform.html#_replace_known_violations\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Replace faulty category identifiers.</p><p>Replaces <cite>type</cite> for <code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">HKCategoryTypeIdentifier</span></code> if <cite>value</cite>\nbetter matches another identifier. Identifier/value combinations that should\nbe replaced are kept in <code class=\"xref py py-const docutils literal notranslate\"><span class=\"pre\">KNOWN_CATEGORY_TYPE_VIOLATIONS</span></code>.</p></dd>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
